import type { FilterFieldError } from './filter-field-error.js';
import type { FilterFieldGroupNode, FilterFieldLeafNode, FilterFieldListNode, FilterFieldNode, FilterFieldNodeBase, FilterFieldStatementNode } from './tree-nodes.js';
/**
 * Return type for the lezer conversion utils.
 * Each util returns the converted node, potential errors, and additional info, if applicable.
 * @internal
 */
export type ConvertedLezerNode<T extends FilterFieldNode | FilterFieldFlatNode | undefined, Info extends Record<string, unknown> = Record<string, never>> = Info extends Record<string, never> ? {
    convertedNode: T;
    errors: FilterFieldError[];
} : {
    convertedNode: T;
    errors: FilterFieldError[];
} & Info;
/**
 * Type used for defining a FilterField logical operator node.
 * @internal
 */
export type FilterFieldLogicalOperatorNode = FilterFieldNodeBase & {
    type: 'LogicalOperator';
    textValue: 'AND' | 'OR';
    value: 'AND' | 'OR';
};
/**
 * Group node that may contain logical operator nodes to convert the lezer syntax tree into a flat
 * tree that will then be sorted according to the logical operator's precedence.
 * @internal
 */
export type FilterFieldFlatGroupNode = Omit<FilterFieldGroupNode, 'children'> & {
    children: FilterFieldFlatNode[];
};
/**
 * Union type for nodes that can appear in a flat filter field tree,
 * including logical operator nodes and flat group nodes (for nested groups).
 * @internal
 */
export type FilterFieldFlatNode = FilterFieldFlatGroupNode | FilterFieldStatementNode | FilterFieldListNode | FilterFieldLeafNode | FilterFieldLogicalOperatorNode;
/**
 * Tree type that includes logical operator nodes before sorting.
 * @internal
 */
export type FilterFieldFlatTree = (FilterFieldFlatGroupNode & {
    version: string;
}) | undefined;
